import { motion } from 'framer-motion';
import { FiUpload, FiArrowRight, FiPlay } from 'react-icons/fi';

const Hero = () => {
  return (
    <section className="relative overflow-hidden bg-gradient-to-br from-gray-900 to-purple-900 py-24 md:py-32">
      {/* Animated neural network background */}
      <div className="absolute inset-0 opacity-10">
        {[...Array(20)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute h-px bg-purple-400/30"
            style={{
              width: `${Math.random() * 200 + 100}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              rotate: Math.random() * 360
            }}
            animate={{
              opacity: [0.1, 0.3, 0.1],
            }}
            transition={{
              duration: 5 + Math.random() * 10,
              repeat: Infinity,
            }}
          />
        ))}
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid lg:grid-cols-2 gap-12 items-center">
        {/* Text Content */}
        <div className="text-center lg:text-left">
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <span className="block">Detect Deepfakes Instantly</span>
            <span className="bg-gradient-to-r from-purple-400 to-cyan-300 bg-clip-text text-transparent">
              with Deep Learning
            </span>
          </motion.h1>

          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg mx-auto lg:mx-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
          >
            Our AI analyzes 287 facial features to detect synthetic media with 99.2% accuracy.
          </motion.p>

          <motion.div 
            className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="#upload-section"
              className="flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-lg font-medium shadow-lg hover:shadow-xl transition-all group"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.98 }}
            >
              <FiUpload className="group-hover:animate-bounce" />
              Analyze Now
              <FiArrowRight className="ml-1 group-hover:translate-x-1 transition-transform" />
            </motion.a>

            <motion.a
              href="#how-it-works"
              className="flex items-center justify-center gap-2 text-white px-6 py-3 rounded-lg font-medium border border-white/20 hover:bg-white/10 transition-colors group"
              whileHover={{ y: -2 }}
            >
              <FiPlay className="text-purple-400 group-hover:text-purple-300" />
              See Technology
            </motion.a>
          </motion.div>
        </div>

        {/* Pure CSS AI Visualization */}
        <div className="relative h-80 md:h-96 lg:h-full">
          <div className="absolute inset-0 rounded-2xl overflow-hidden border border-white/10 bg-gradient-to-br from-purple-900/30 to-blue-900/20 flex items-center justify-center">
            
            {/* Face scan animation */}
            <div className="relative w-64 h-64">
              {/* Face outline */}
              <div className="absolute inset-0 rounded-full border-2 border-white/20 flex items-center justify-center">
                <div className="w-3/4 h-3/4 rounded-full border border-white/10" />
              </div>
              
              {/* Scanning effect */}
              <motion.div
                className="absolute top-0 left-0 right-0 h-0.5 bg-gradient-to-r from-transparent via-cyan-400/80 to-transparent"
                animate={{
                  y: ['0%', '100%']
                }}
                transition={{
                  duration: 2,
                  repeat: Infinity,
                  ease: 'linear'
                }}
              />
              
              {/* Detection points */}
              {[...Array(8)].map((_, i) => (
                <motion.div
                  key={i}
                  className="absolute w-2 h-2 rounded-full bg-purple-400"
                  style={{
                    left: `${50 + 30 * Math.cos((i * Math.PI) / 4)}%`,
                    top: `${50 + 30 * Math.sin((i * Math.PI) / 4)}%`,
                  }}
                  animate={{
                    scale: [1, 1.5, 1],
                    opacity: [0.6, 1, 0.6]
                  }}
                  transition={{
                    duration: 2,
                    repeat: Infinity,
                    delay: i * 0.2
                  }}
                />
              ))}
              
              {/* Result indicator */}
              <motion.div
                className="absolute bottom-4 right-4 bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-md shadow-lg"
                animate={{
                  scale: [1, 1.2, 1],
                  opacity: [0.8, 1, 0.8]
                }}
                transition={{
                  duration: 3,
                  repeat: Infinity
                }}
              >
                AI DETECTED
              </motion.div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
